/**
 * Draw multiple candidates for selection (without replacement)
 * Tier-diverse first: one from each available tier, then weight-based fill.
 * Supports duplicatePolicy="forbid" and session state filtering.
 */
drawForSelection(count: number = ${choiceCount}): T[] {
  if (this.items.length === 0) {
    print(`[Rune Weaver] ${className}: No items in pool`);
    return [];
  }

  const result: T[] = [];
  const drawnIds = new Set<string>();
  const ownedIds = new Set<string>(${hasSessionState ? "this.sessionState.ownedTalentIds" : "[]"});

  // Filter available items respecting session state and ownership
  let availableItems = this.items.filter(item => {
    const id = (item.item as any).id as string;
    if (ownedIds.has(id)) return false;
    ${hasSessionState ? `if (!this.sessionState.remainingTalentIds.includes(id)) return false;` : ""}
    return true;
  });

  if (availableItems.length === 0) {
    print(`[Rune Weaver] ${className}: No available items in session pool`);
    return [];
  }

  // Group by tier for tier-diverse selection
  const tierGroups = new Map<number, WeightedItem<T>[]>();
  for (const item of availableItems) {
    const tier = item.tier ?? 0;
    if (!tierGroups.has(tier)) tierGroups.set(tier, []);
    tierGroups.get(tier)!.push(item);
  }

  const sortedTiers = Array.from(tierGroups.keys()).sort((a, b) => a - b);

  // Phase 1: Draw one from each tier until count reached or tiers exhausted
  for (const tier of sortedTiers) {
    if (result.length >= count) break;
    const group = tierGroups.get(tier)!.filter(item => {
      const id = (item.item as any).id as string;
      return !drawnIds.has(id);
    });
    if (group.length === 0) continue;

    const tierTotalWeight = group.reduce((sum, item) => sum + item.weight, 0);
    if (tierTotalWeight <= 0) continue;

    let random = RandomFloat(0, tierTotalWeight);
    let drawn: WeightedItem<T> | null = null;
    for (const item of group) {
      random -= item.weight;
      if (random <= 0) {
        drawn = item;
        break;
      }
    }

    if (drawn) {
      const itemId = (drawn.item as any).id as string;
      if ("${duplicatePolicy}" === "forbid" && drawnIds.has(itemId)) {
        continue;
      }
      result.push(drawn.item);
      drawnIds.add(itemId);
      // Remove from availableItems to prevent re-selection in phase 2
      const idx = availableItems.indexOf(drawn);
      if (idx > -1) availableItems.splice(idx, 1);
    }
  }

  // Phase 2: Weight-based fill for remaining slots
  while (result.length < count && availableItems.length > 0) {
    if ("${duplicatePolicy}" === "forbid" && drawnIds.size >= availableItems.length + result.length) {
      print(`[Rune Weaver] ${className}: Cannot draw more unique items (duplicatePolicy="forbid")`);
      break;
    }

    const currentTotalWeight = availableItems.reduce((sum, item) => sum + item.weight, 0);
    if (currentTotalWeight <= 0) {
      print(`[Rune Weaver] ${className}: No weight available in pool`);
      break;
    }

    let random = RandomFloat(0, currentTotalWeight);
    let drawn: WeightedItem<T> | null = null;
    for (const item of availableItems) {
      random -= item.weight;
      if (random <= 0) {
        drawn = item;
        break;
      }
    }

    if (drawn) {
      const itemId = (drawn.item as any).id as string;
      if ("${duplicatePolicy}" === "forbid" && drawnIds.has(itemId)) {
        continue;
      }
      result.push(drawn.item);
      drawnIds.add(itemId);
      const idx = availableItems.indexOf(drawn);
      if (idx > -1) availableItems.splice(idx, 1);
    }
  }

  ${hasSessionState ? `// Update currentChoiceIds in session state
  this.sessionState.currentChoiceIds = result.map(item => (item as any).id);` : ""}

  return result;
}
